@@ -21,7 +21,7 @@ document.registerElement('a-example-link', {

         // Link to source code.
         var githubLink =
-          'https://github.com/MozVR/aframe-core/blob/master/examples/';
+          'https://github.com/aframevr/aframe-core/blob/master/examples/';
         viewSourceLink = document.createElement('a');
         viewSourceLink.setAttribute('href',
           githubLink + href + 'index.html');

@@ -68,12 +68,12 @@
               break;
             case greenCylinder:
               var oldVisible = greenCylinder.getComputedAttribute('visible');
-              // See issue: https://github.com/MozVR/aframe-core/issues/349
+              // See issue: https://github.com/aframevr/aframe-core/issues/349
               if (oldVisible === null) { oldVisible = true; }
               greenCylinder.setAttribute('visible', !oldVisible);
               break;
             case pinkTorus:
-              // Yes, this is gross. See https://github.com/MozVR/aframe-core/issues/235
+              // Yes, this is gross. See https://github.com/aframevr/aframe-core/issues/235
               var oldMaterial = pinkTorus.getComputedAttribute('material');
               var oldOpacity = oldMaterial.opacity;
               var newOpacity = oldOpacity === 1 ? 0 : 1;

